solution: ```class Solution {
    public List<Integer> splitIntoFibonacci(String num) {
        int n = num.length();
        for (int i = 1; i <= Math.min(10, n / 2); ++i) {
            for (int j = 1; j <= Math.min(10, n - i); ++j) {
                if (i + j >= n) break;
                List<Integer> res = new ArrayList<>();
                String s1 = num.substring(0, i);
                String s2 = num.substring(i, i + j);
                if ((s1.length() > 1 && s1.charAt(0) == '0') || (s2.length() > 1 && s2.charAt(0) == '0')) continue;
                long a, b;
                try {
                    a = Long.parseLong(s1);
                    b = Long.parseLong(s2);
                } catch (NumberFormatException e) { continue; }
                if (a > Integer.MAX_VALUE || b > Integer.MAX_VALUE) continue;
                res.add((int) a);
                res.add((int) b);
                int pos = i + j;
                boolean ok = true;
                while (pos < n) {
                    long next = a + b;
                    if (next > Integer.MAX_VALUE) { ok = false; break; }
                    String ns = String.valueOf(next);
                    if (!num.startsWith(ns, pos)) { ok = false; break; }
                    res.add((int) next);
                    pos += ns.length();
                    a = b;
                    b = next;
                }
                if (ok && res.size() >= 3) return res;
            }
        }
        return new ArrayList<>();
    }
}
